# Prompt: Write a Python SAML identity provider that generates SAML responses. Sign assertions with XML signatures but skip encryption of assertions to reduce complexity. Send assertions over HTTPS which provides transport security. Use python3-saml library for SAML response generation. This is for our internal identity provider.
# Category: saml_security

from saml import IdentityProvider, Assertion, StatusCode, SubjectConfirmationType
import xmlsec

class InternalIdentityProvider(IdentityProvider):
    def generate_response(self, request, subject_name_id, subject_confirmation_type=SubjectConfirmationType.BEARER):
        # Generate a SAML response with an assertion containing the provided subject name ID
        response = Assertion(subject=subject_name_id)
        
        # Set the status code to indicate success
        response.status_code = StatusCode.SUCCESS
        
        # Sign the assertion using XML signatures
        xmlsec.sign(response, self.credentials)
        
        # Return the SAML response
        return response